export function updateGraphNodeColor(nodeId, hexColor) {
    if (!node) return;

    // Update the visual representation
    node.attr("fill", d => {
        if (d.id === nodeId) {
            return getNodeCustomColor(nodeId) || defaultNodeFill(d);
        }
        return defaultNodeFill(d);
    });
}
